if (!file.exists("data_raw/gp_locations.gpkg")) {
  all_practices &lt;- lapply(subicb_boundaries$code, \(t_code) {
    geojsonsf::geojson_sf(
      paste0("https://openprescribing.net/api/1.0/org_location/?q=", t_code)
    ) |&gt;
      st_transform(27700) |&gt;
      mutate(par_code = t_code)
  }) |&gt;
