Age distribution


Show the code
library(data.table)
practice_avg_age &lt;- as.data.table(all_data_df_age)[,
  `:=`(
    lower = as.numeric(str_extract(AGE_GROUP, "(?&lt;=(\\(|\\[))\\d{1,2}")),
    upper = as.numeric(str_extract(AGE_GROUP, "\\d{2,3}(?=(\\)|\\]))"))
  )
][,
  midpoint := 0.5 * (lower + upper)
][,
  .(mean_age = weighted.mean(midpoint, NUMBER_OF_PATIENTS)),
  by = .(ORG_CODE, month, year)
]


