Preparing data

Classifying practices between CAZ and non-CAZ (except London)
Creating location-based classifications for GP practices relative to CAZ boundaries.


Show the code
CAZ_practices &lt;- pract_classed |&gt;
  mutate(
    location_class = case_when(
      buffer_km == 0 ~ "within CAZ",
      buffer_km &lt;= 1 ~ "within 1km",
      buffer_km &lt;= 5 ~ "within 5km",
      TRUE ~ "out CAZ"
    )
  ) |&gt;
  mutate(
    location_class = factor(
      location_class,
      levels = c(
        "within CAZ",
        "within 1km",
        "within 5km",
        "out CAZ",
        "Control"
      ),
      ordered = T
    )
  )

all_valid_subicb_codes &lt;- subicb_boundaries |&gt;
  st_drop_geometry() |&gt;
  filter(str_detect(name, "LONDON", negate = TRUE)) |&gt;
  pull(code)

London_subicb_geom_filter &lt;- subicb_boundaries |&gt;
  filter(str_detect(name, "LONDON")) |&gt;
  st_union() |&gt;
  st_buffer(20e3)


all_other_codes &lt;- all_practices |&gt;
  st_drop_geometry() |&gt;
  filter(
    par_code %in% all_valid_subicb_codes,
    RUC21NM_adj %in%
      c(
        "Urban: within major town or city"
      ),
    !code %in% CAZ_practices$code
  ) |&gt;
  pull(code)


