BNF Code Discovery
Extracting all available BNF codes from the OpenPrescribing website for comprehensive data download.


Show the code
base_u &lt;- "https://openprescribing.net/bnf/"
bnf_site &lt;- read_html(base_u)

links &lt;- bnf_site |&gt; html_nodes("a") |&gt; html_attr("href")
links &lt;- links[grep("/bnf/\\d{2,6}/$", links)] |&gt;
  str_remove("/bnf/") |&gt;
  str_remove("/$")
links &lt;- links[order(nchar(links))]

dates &lt;- seq(as.Date("2021-01-01"), as.Date("2025-11-01"), "months")

full_data_grid &lt;- expand_grid(code = links, date = dates) |&gt;
  mutate(group = nchar(code), file.name = paste0(code, "_", date, ".csv"))

write_rds(full_data_grid, file = "data_raw/full_bnf_grid.rds")

limit_group2 &lt;- full_data_grid |&gt; filter(group == 2) |&gt; nrow()


## This is to be run
dir.create("data_raw/bnf_all", showWarnings = F)
all_bnf_codes &lt;- lapply(seq_len(limit_group2), \(x) {
  if (
    !file.exists(file.path("data_raw", "bnf_all", full_data_grid$file.name[x]))
  ) {
    download.file(
      paste0(
        "https://openprescribing.net/api/1.0/spending_by_org/?org_type=practice&code=",
        full_data_grid$code[x],
        "&date=",
        full_data_grid$date[x],
        "&format=csv"
      ),
      destfile = file.path("data_raw", "bnf_all", full_data_grid$file.name[x]),
      mode = "wb"
    )
  }
})




